const item = $input.first().json;
const auth = item.headers?.authorization || '';
const EXPECTED = 'Bearer simarro_Z2O40vQbqve2YZ3Ksn2JsEQCcJqAh6L8BO8mxvbqwTE';
if (auth !== EXPECTED) {
  return [{json: {valid: false, status: 401, message: 'Unauthorized'}}];
}
const body = item.body;
if (!body || typeof body !== 'object') {
  return [{json: {valid: false, status: 400, message: 'Body required'}}];
}
const VALID = ['valoracion','valoracion_quick','capacidad','simulacion_hipoteca','personal_shopper','inversion','contacto_propiedad'];
if (!VALID.includes(body.formType)) {
  return [{json: {valid: false, status: 400, message: 'Invalid formType: '+body.formType}}];
}
if (!body.fields || typeof body.fields !== 'object') {
  return [{json: {valid: false, status: 400, message: 'fields required'}}];
}
if (!body.fields.telefono) {
  return [{json: {valid: false, status: 400, message: 'telefono required'}}];
}
return [{json: {valid: true, body, headers: item.headers || {}, params: item.params || {}}}];

const body = $('Auth & Validate').first().json.body;
const f = body.fields;

function normPhone(p) {
  let s = String(p || '').replace(/[\s()-]/g, '');
  if (!s) return '';
  if (s.startsWith('+')) return s;
  if (s.startsWith('00')) return '+' + s.slice(2);
  if (s.startsWith('34') && s.length >= 11) return '+' + s;
  if (/^\d{9}$/.test(s)) return '+34' + s;
  return s;
}

