const lead_cfs = [];
function pushVal(fid, v, type){
  if (v === undefined || v === null || v === '') return;
  if (type === 'num') lead_cfs.push({field_id: fid, values:[{value: Number(v)}]});
  else lead_cfs.push({field_id: fid, values:[{value: String(v)}]});
}
function pushEnum(fid, enumId){
  if (enumId === undefined || enumId === null) return;
  lead_cfs.push({field_id: fid, values:[{enum_id: Number(enumId)}]});
}
function precioObjetivoEnumId(p){
  const n = Number(p);
  if (!isFinite(n) || n <= 0) return null;
  if (n < 200000) return 1019859; // Menos de 200k
  if (n < 300000) return 1019861; // 200k-300k
  if (n < 400000) return 1019863; // 300k-400k
  return 1019865;                  // Más de 400k
}
const M_TIPO = {piso:'Piso',atico:'Ático',duplex:'Dúplex',chalet:'Chalet',local_oficina:'Local-Oficina',otro:'Otro'};
