const M_PRES = {'100k_300k':'100k-300k','300k_600k':'300k-600k','600k_1m':'600k-1M',mas_1m:'Más de 1M',no_definido:'No definido'};

if (f.email) pushVal(CFS.email_lead, f.email);
if (body.formType === 'valoracion' || body.formType === 'valoracion_quick') {
  pushVal(CFS.tipo_vivienda, M_TIPO[f.tipoVivienda]);
  pushVal(CFS.zona, f.zona);
}
if (body.formType === 'valoracion') {
  pushVal(CFS.superficie, f.superficie, 'num');
  pushVal(CFS.habitaciones, f.habitaciones);
  pushVal(CFS.estado_vivienda, M_EST[f.estado]);
  pushVal(CFS.plazo_venta, M_PLAZO[f.plazoVenta]);
}
