    return (r < 0 ? '-' : '') + s + ' €';
  };
  const price = Number(f.propertyPrice) || 0;
  const down  = Number(f.downPayment) || 0;
  const pct = price > 0 ? Math.round((down / price) * 100) : null;
  const rate = (f.annualInterest !== undefined && f.annualInterest !== null) ? String(f.annualInterest).replace('.', ',') : null;
  const lines = ['Simulador hipoteca:'];
  if (f.propertyPrice) lines.push('· Precio inmueble: ' + eur(f.propertyPrice));
  if (f.downPayment !== undefined) lines.push('· Entrada: ' + eur(f.downPayment) + (pct !== null ? ' (' + pct + '%)' : ''));
  if (f.termYears) lines.push('· Plazo: ' + f.termYears + ' años');
  if (rate !== null && f.rateType) lines.push('· Tipo: ' + f.rateType + ' @ ' + rate + '%');
  if (f.monthlyPayment) lines.push('· Cuota mensual: ' + eur(f.monthlyPayment));
  if (f.totalInterest) lines.push('· Intereses totales: ' + eur(f.totalInterest));
  if (f.totalPaid) lines.push('· Coste total: ' + eur(f.totalPaid));
  notasParts.push(lines.join('\n'));
}
if (body.formType === 'capacidad') {
  const eur = (n) => {
    if (n === undefined || n === null) return null;
    const r = Math.round(Number(n));
    const s = String(Math.abs(r)).replace(/\B(?=(\d{3})+(?!\d))/g, '.');
    return (r < 0 ? '-' : '') + s + ' €';
  };
